from math import gcd

def solution(limit=1500000):
    counts = [0] * (limit + 1)
    m_limit = int((limit // 2)**0.5)
    for m in range(2, m_limit + 1):
        for n in range(1, m):
            # primitive triple conditions
            if (m - n) % 2 == 1 and gcd(m, n) == 1:
                p = 2 * m * (m + n)
                # account for all multiples
                for multiple_p in range(p, limit + 1, p):
                    counts[multiple_p] += 1
    return sum(1 for c in counts if c == 1)


if __name__ == "__main__":
    print(solution(1500000))
